   333|function resolveSendBranch(
   334|  deliveryBranch: DeliveryBranchStatus['branch'],
   335|  runtimeSource: RuntimeDebugSnapshot['source'],
   336|  httpStatus: string,
   337|): SendBranchProofRow {
   338|  if (deliveryBranch === 'not_observed') {
   339|    return { branch: null, label: 'pending', context: 'no send observed' };
   340|  }
   341|
   342|  const statusFragment = httpStatus !== 'pending' && httpStatus !== 'none' ? ` · ${httpStatus}` : '';
   343|
   344|  if (deliveryBranch === 'remote_db_insert') {
   345|    if (runtimeSource === 'remote_api' || runtimeSource === 'local_app_brain') {
   346|      return { branch: 'primary_realtime', label: 'primary_realtime', context: `assistant db insert${statusFragment}` };
   347|    }
   348|    if (runtimeSource === 'provider_fallback') {
   349|      return { branch: 'alternate_shared', label: 'alternate_shared', context: `gateway db insert${statusFragment}` };
   350|    }
   351|    return { branch: 'primary_realtime', label: 'primary_realtime', context: `db insert · source ${runtimeSource}${statusFragment}` };
   352|  }
   353|
   354|  if (deliveryBranch === 'local_fallback') {
   355|    return { branch: 'snapshot_fallback', label: 'snapshot_fallback', context: `local fallback path${statusFragment}` };
   356|  }
   357|
   358|  if (deliveryBranch === 'auth_session_failure') {
   359|    return { branch: 'local_only', label: 'local_only', context: `auth/session unavailable${statusFragment}` };
   360|  }
   361|
   362|  return { branch: 'local_only', label: 'local_only', context: `unresolved branch${statusFragment}` };
   363|}
